Fetching all vehicles<pre><code>const res = await client.queries.listVehicles();

// res.listVehicles is Vehicle[] — fully typed
res.listVehicles.forEach(v =&gt; {
  console.log(`${v.brand} ${v.model} (${v.year})`);
});

// Filter with full type safety
const electrics = res.listVehicles.filter(v =&gt; v.fuelType === FuelType.ELECTRIC);
</code></pre>
